import React from "react";

function formatCoordinate(value) {
  if (typeof value !== "number" || Number.isNaN(value)) {
    return "--";
  }

  return value.toFixed(3);
}

function formatNumber(value, digits = 2) {
  if (typeof value !== "number" || Number.isNaN(value)) {
    return "--";
  }

  return value.toFixed(digits);
}

export default function StatusBar({ position, lastUpdated, loading, error }) {
  return (
    <section
      style={{
        marginTop: "12px",
        border: "1px solid #2b3754",
        borderRadius: "10px",
        padding: "12px 14px",
        backgroundColor: "rgba(11, 16, 32, 0.82)",
        display: "flex",
        flexWrap: "wrap",
        gap: "12px",
        fontSize: "14px",
        color: "#e2e8f0",
      }}
    >
      <span>Latitude: {formatCoordinate(position?.latitude)}</span>
      <span>Longitude: {formatCoordinate(position?.longitude)}</span>
      <span>Altitude: {formatNumber(position?.altitude)} km</span>
      <span>Velocity: {formatNumber(position?.velocity)} km/h</span>
      <span>
        Last Updated:{" "}
        {lastUpdated ? lastUpdated.toLocaleTimeString() : loading ? "Loading..." : "--"}
      </span>
      {error ? <span style={{ color: "#fca5a5" }}>Error: {error}</span> : null}
    </section>
  );
}
